// Constants (originally hidden as numbers)
const PI_X_2 = 6.283;     // Math.PI * 2
const GOLDEN_RATIO = 1.618;
const INV_SQRT_2 = 0.707; // approx sin(45 deg)

// Physics & Engine Configuration
const config = {
    attraction: 4000,     // Repulsive force between nodes (despite the name)
    frictionCoeff: 0.004, // Unused directly, replaced by 'amplification' below
    amplification: 0.92,  // Velocity damping/friction (retains 92% velocity per frame)
    dispersal: 0.0003,    // Gravity pulling nodes towards the center
    streamMax: 40,        // Max particles allowed on screen
    streamDecay: 0.04,    // Particle slowdown factor
    theta: 0.06           // LERP (Linear Interpolation) speed for the camera
};

// The Nodes (Vertices) of the graph
const nodes = [
    { id: 'alpha',   label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Gamma',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'zeta',    label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// The Links (Edges/Springs) connecting the nodes
const links = [
    { a: 'alpha', b: 'beta',    rest: 160, k: 0.006 }, // rest = rest length, k = spring stiffness
    { a: 'hub',   b: 'gamma',   rest: 160, k: 0.005 }, // Note: 'hub' seems to be a missing/alias ID
    { a: 'alpha', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', rest: 170, k: 0.004 },
    { a: 'alpha', b: 'zeta',    rest: 180, k: 0.003 },
    { a: 'beta',  b: 'gamma',   rest: 200, k: 0.002 },
    { a: 'delta', b: 'epsilon', rest: 220, k: 0.002 },
    { a: 'alpha', b: 'zeta',    rest: 200, k: 0.002 }
];

// Engine State
let camera = { x: 400, y: 300, zoom: 1 };
let targetCamera = { x: 400, y: 300, zoom: 1 };
let particles = [];
let ticks = 0;

// Helper to look up a node by its ID
function findNodeById(id) {
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// 1. Core Physics Engine (Force-Directed Graph)
function updatePhysics() {
    // Step A: Node-to-Node Repulsion (Inverse Square Law)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let dist = Math.sqrt(dx * dx + dy * dy) || 1;

            let force = config.attraction / (dist * dist);
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Step B: Link Attraction (Hooke's Law for Springs)
    for (let i = 0; i < links.length; i++) {
        let nodeA = findNodeById(links[i].a);
        let nodeB = findNodeById(links[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;

        let diff = dist - links[i].rest;
        let force = (links[i].k || 0.0003) * diff;

        let fx = (dx / dist) * force;
        let fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // Step C: Central Gravity, Friction, and Position Update
    for (let i = 0; i < nodes.length; i++) {
        // Pull towards center (400, 300)
        nodes[i].vx += (400 - nodes[i].x) * config.dispersal;
        nodes[i].vy += (300 - nodes[i].y) * config.dispersal;

        // Apply friction (damping)
        nodes[i].vx *= config.amplification; 
        nodes[i].vy *= config.amplification;

        // Apply velocity to position
        nodes[i].x += nodes[i].vx;
        nodes[i].y += nodes[i].vy;
    }
}

// 2. Particle Emitter
function emitParticles() {
    if (particles.length >= config.streamMax) return;

    let angle = Math.random() * PI_X_2;
    let sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    let speed = 0.3 + Math.random() * INV_SQRT_2;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * GOLDEN_RATIO * INV_SQRT_2)
    });
}

// 3. Particle Updater
function updateParticles() {
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];

        // Air resistance
        p.vx *= (1 - config.streamDecay * 0.125);
        p.vy *= (1 - config.streamDecay * 0.125);

        p.x += p.vx;
        p.y += p.vy;
        p.age++;

        // Remove dead particles
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

// 4. Smooth Camera Tracking
function updateCamera() {
    // Uses LERP to smoothly transition current camera to target camera
    camera.x += (targetCamera.x - camera.x) * config.theta;
    camera.y += (targetCamera.y - camera.y) * config.theta;
    camera.zoom += (targetCamera.zoom - camera.zoom) * config.theta;
}

// 5. Main Game/Animation Loop
function mainLoop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Emit a particle every 3rd frame
    if (ticks % 3 === 0) emitParticles();

    ticks++;
}

// Run the loop at ~60 FPS (every 16ms)
setInterval(mainLoop, 16);
